// Combine metrics from Gateway API and local logs
const metrics = $node['Fetch Gateway Metrics'].json || {};
const logRaw = $node['Collect Token Usage'].json.stdout || '{}';
let logUsage;
try {
  logUsage = JSON.parse(logRaw);
} catch {
  logUsage = { claude_requests: 0, gemini_requests: 0 };
}

// Task stats from Gateway
const tasks = metrics.tasks || { pending: 0, in_progress: 0, done: 0, blocked: 0 };
const mode = metrics.mode || { current_mode: 'unknown' };

// Token usage thresholds
const CLAUDE_DAILY_LIMIT = parseInt($env.CLAUDE_DAILY_LIMIT || '1000');
const GEMINI_DAILY_LIMIT = parseInt($env.GEMINI_DAILY_LIMIT || '500');

const claude_pct = (logUsage.claude_requests / CLAUDE_DAILY_LIMIT) * 100;
const gemini_pct = (logUsage.gemini_requests / GEMINI_DAILY_LIMIT) * 100;

// Generate alerts based on thresholds
const alerts = [];
const suggestions = [];

// Over 80% usage alert
if (claude_pct > 80) alerts.push(`Claude: ${logUsage.claude_requests}/${CLAUDE_DAILY_LIMIT} (${claude_pct.toFixed(0)}%)`);
if (gemini_pct > 80) alerts.push(`Gemini: ${logUsage.gemini_requests}/${GEMINI_DAILY_LIMIT} (${gemini_pct.toFixed(0)}%)`);

// Under 30% usage — suggest more tasks
if (claude_pct < 30 && tasks.pending === 0) {
  suggestions.push('Claude usage < 30% and no pending tasks. Consider scheduling more work.');
}
if (gemini_pct < 30 && tasks.pending === 0) {
  suggestions.push('Gemini usage < 30% and no pending tasks. Resources are underutilized.');
}

const has_alert = alerts.length > 0;
const has_suggestion = suggestions.length > 0;

let message = `📊 *[Daily Usage Report]*\n`;
message += `Mode: ${mode.current_mode}\n`;
message += `Tasks — Done: ${tasks.done} | Pending: ${tasks.pending} | Blocked: ${tasks.blocked}\n`;
message += `Claude: ${logUsage.claude_requests}/${CLAUDE_DAILY_LIMIT} (${claude_pct.toFixed(0)}%)\n`;
message += `Gemini: ${logUsage.gemini_requests}/${GEMINI_DAILY_LIMIT} (${gemini_pct.toFixed(0)}%)`;

if (has_alert) message += `\n\n⚠️ *High Usage:* ${alerts.join(', ')}`;
if (has_suggestion) message += `\n\n💡 *Suggestion:* ${suggestions.join('. ')}`;

return [{
  json: {
    message,
    has_alert,
    has_suggestion,
    claude_pct: claude_pct.toFixed(1),
    gemini_pct: gemini_pct.toFixed(1),
    tasks,
    mode: mode.current_mode
  }
}];
